func nvidiaDriverReconcileRequests(ctx context.Context, c client.Reader, source *nvidiav1alpha1.NVIDIADriver) []reconcile.Request {
	logger := log.FromContext(ctx)
	reconcileRequests := []reconcile.Request{}
	seen := map[types.NamespacedName]struct{}{}
	addRequest := func(obj client.Object) {
		if obj == nil || obj.GetName() == "" {
			return
		}
		namespacedName := types.NamespacedName{
			Name:      obj.GetName(),
			Namespace: obj.GetNamespace(),
		}
		if _, ok := seen[namespacedName]; ok {
			return
		}
		seen[namespacedName] = struct{}{}
		reconcileRequests = append(reconcileRequests, reconcile.Request{NamespacedName: namespacedName})
	}

	addRequest(source)

	list := &nvidiav1alpha1.NVIDIADriverList{}
	if err := c.List(ctx, list); err != nil {
		logger.Error(err, "Unable to list NVIDIADriver resources")
		return reconcileRequests
	}

	for i := range list.Items {
		addRequest(&list.Items[i])
	}

	return reconcileRequests
