	}

	// Watch for changes to the primary resource NVIDIADriver. Any NVIDIADriver
	// change can affect global nodeSelector conflict validation, so enqueue peers.
	nvidiaDriverMapFn := func(ctx context.Context, driver *nvidiav1alpha1.NVIDIADriver) []reconcile.Request {
		return nvidiaDriverReconcileRequests(ctx, mgr.GetClient(), driver)
	}
	err = c.Watch(source.Kind(
		mgr.GetCache(),
		&nvidiav1alpha1.NVIDIADriver{},
